mapper.select:

WHERE 1 = 1



       AND (m.from_agent_id = #{withId} OR m.to_agent_id = #{withId})


      AND m.to_agent_id = #{agentId}


      AND m.from_agent_id = #{agentId}


      AND (m.from_agent_id = #{agentId} OR m.to_agent_id = #{agentId})



  AND m.status = #{status}

ORDER BY m.created_at ASC
LIMIT #{limit}

mapper.update:
UPDATE t_ai_message
   SET read_at = NOW()
 WHERE message_id = #{messageId}
   AND to_agent_id = #{agentId}
   AND read_at IS NULL

UPDATE t_ai_message
   SET status = 'failed',
       error_reason = #{errorReason}
 WHERE message_id = #{messageId}
   AND status = 'sent'

mapper.select:

WHERE (af.owner_account_sn = #{ownerAccountSn}
   OR at.owner_account_sn = #{ownerAccountSn})

  AND m.status = #{status}


  AND m.from_agent_id = #{fromAgentId}


  AND m.to_agent_id = #{toAgentId}


  AND m.content ILIKE CONCAT('%', #{q}, '%')

ORDER BY m.created_at DESC
LIMIT #{limit}

